proof:
obtain ⟨ g, hg ⟩ := hf;
constructor;
· intro W h k h_eq;
  apply_fun ( · ≫ g ) at h_eq;
  simp_all +decide [ Category.assoc ];
  convert h_eq using 1;
  · exact (comp_id _).symm
  · exact (comp_id _).symm
· intro Z h k h_eq;
  -- Using the fact that $g \circ f = \text{id}_Y$, we can simplify the equation $g \circ (f \circ h) = g \circ (f \circ k)$ to $h = k$.
  have h_simp : (g ≫ f) ≫ h = (g ≫ f) ≫ k := by
    simp +decide [ h_eq, Category.assoc ];
  rw [ hg.2, Category.id_comp, Category.id_comp ] at h_simp ; aesop

